	
Function Happy_Birthday
{

    #Author: Trevor Sullivan (@pcgeek86)
    #Date: 2013-10-10
    #Description: Happy Birthday song, converted from Unicode to Base64 encoding, written with @RodTrent in mind.
    #Update: The Base64 encoded version was just for portability.
    #It's easy to decode Base64, but eiterh way, I included the original code below.
     
    
    #powershell.exe -encodedCommand ;
     
    $BeepList = @(
        @{ Pitch = 1000; Length = 300; };
        @{ Pitch = 1000; Length = 200; };
        @{ Pitch = 1150; Length = 500; };
        @{ Pitch = 1000; Length = 500; };
        @{ Pitch = 1350; Length = 500; };
        @{ Pitch = 1250; Length = 800; };
     
        @{ Pitch = 1000; Length = 300; };
        @{ Pitch = 1000; Length = 200; };
        @{ Pitch = 1150; Length = 500; };
        @{ Pitch = 1000; Length = 500; };
        @{ Pitch = 1500; Length = 500; };
        @{ Pitch = 1350; Length = 800; };
     
        @{ Pitch = 1000; Length = 300; };
        @{ Pitch = 1000; Length = 200; };
        @{ Pitch = 2000; Length = 500; };
        @{ Pitch = 1700; Length = 500; };
        @{ Pitch = 1370; Length = 500; };  # Doesn't sound quite right
        @{ Pitch = 1225; Length = 500; };  # Doesn't sound quite right
        @{ Pitch = 1150; Length = 500; };  # Doesn't sound quite right
        @{ Pitch = 1800; Length = 300; };
        @{ Pitch = 1800; Length = 200; };
        @{ Pitch = 1700; Length = 500; };
        @{ Pitch = 1370; Length = 700; };
        @{ Pitch = 1500; Length = 500; };
        @{ Pitch = 1370; Length = 500; };
        );
     
    foreach ($Beep in $BeepList) {
        [System.Console]::Beep($Beep['Pitch'], $Beep['Length']);
    }

}


